    28→uint64_t Utility::grpcToHttpStatus(Status::GrpcStatus grpc_status) {
    29→  // From https://cloud.google.com/apis/design/errors#handling_errors.
    30→  switch (grpc_status) {
    31→  case Status::WellKnownGrpcStatus::Ok:
    32→    return 200;
    33→  case Status::WellKnownGrpcStatus::Canceled:
    34→    // Client closed request.
    35→    return 499;
    36→  case Status::WellKnownGrpcStatus::Unknown:
    37→    // Internal server error.
    38→    return 500;
    39→  case Status::WellKnownGrpcStatus::InvalidArgument:
    40→    // Bad request.
    41→    return 400;
    42→  case Status::WellKnownGrpcStatus::DeadlineExceeded:
    43→    // Gateway Time-out.
    44→    return 504;
    45→  case Status::WellKnownGrpcStatus::NotFound:
    46→    // Not found.
    47→    return 404;
    48→  case Status::WellKnownGrpcStatus::AlreadyExists:
    49→    // Conflict.
    50→    return 409;
    51→  case Status::WellKnownGrpcStatus::PermissionDenied:
    52→    // Forbidden.
    53→    return 403;
    54→  case Status::WellKnownGrpcStatus::ResourceExhausted:
    55→    //  Too many requests.
    56→    return 429;
    57→  case Status::WellKnownGrpcStatus::FailedPrecondition:
    58→    // Bad request.
    59→    return 400;
    60→  case Status::WellKnownGrpcStatus::Aborted:
    61→    // Conflict.
    62→    return 409;
    63→  case Status::WellKnownGrpcStatus::OutOfRange:
    64→    // Bad request.
    65→    return 400;
    66→  case Status::WellKnownGrpcStatus::Unimplemented:
    67→    // Not implemented.
    68→    return 501;
    69→  case Status::WellKnownGrpcStatus::Internal:
    70→    // Internal server error.
    71→    return 500;
    72→  case Status::WellKnownGrpcStatus::Unavailable:
    73→    // Service unavailable.
    74→    return 503;
    75→  case Status::WellKnownGrpcStatus::DataLoss:
    76→    // Internal server error.
    77→    return 500;
    78→  case Status::WellKnownGrpcStatus::Unauthenticated:
    79→    // Unauthorized.
    80→    return 401;
    81→  case Status::WellKnownGrpcStatus::InvalidCode:
    82→  default:
    83→    // Internal server error.
    84→    return 500;
    85→  }
